class Solution {
    public int shipWithinDays(int[] weights, int days) {
        int left = 0, right = 0;
        for (int w : weights) {
            left = Math.max(left, w);
            right += w;
        }
        while (left < right) {
            int mid = left + (right - left) / 2;
            int cur = 1, curSum = 0;
            for (int w : weights) {
                if (curSum + w > mid) {
                    cur++;
                    curSum = w;
                } else {
                    curSum += w;
                }
            }
            if (cur <= days) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }
}
```
efficiency: HIGH
time complexity: O(n log m)
space complexity: O(1)
